def rediscache(*args, **kwargs):
    def outer_wrapper(func):
        def inner_wrapper():
            cache = kwargs["redis"].get(''.join([func.__name__, kwargs]))

            if not cache:
                cache = func()

                kwargs['redis'].setex(
                    key=''.join([func.__name__, kwargs]), value=json.dumps(cache), timeout=240)
            else:
                print('Found Cache', json.loads(cache))
        return inner_wrapper
    return outer_wrapper


